const sd=$getWorkflowStaticData('global');
const execId=String($execution.id ?? 'manual');
const nowIso=new Date().toISOString();
const METRICS_DEFAULTS={"rulesPages":0,"rulesTotal":0,"rulesEligible":0,"rulesSkippedDay":0,"rulesSkippedExisting":0,"invoicesPrefetchCalls":0,"invoicesPrefetchCount":0,"itemBatchQueries":0,"itemsFetched":0,"createInvoices":0,"createItems":0,"updateItemInvoiceLinks":0,"updateParcelasPagas":0};

const normalizeNumber=(value,fallback,min=1,max=Number.MAX_SAFE_INTEGER)=>{
  const n=Number(value);
  if(!Number.isFinite(n)) return fallback;
  const normalized=Math.floor(n);
  return Math.min(max,Math.max(min,normalized));
};
const isIsoDate=(value)=>/^\d{4}-\d{2}-\d{2}$/.test(String(value||'').slice(0,10));
const normalizeIsoDate=(value,fallbackValue,fieldName,notes)=>{
  const candidate=String(value ?? '').trim().slice(0,10);
  if(isIsoDate(candidate)) return candidate;
  notes.push({field:fieldName,from:value ?? null,to:fallbackValue});
  return fallbackValue;
};
const validatePositiveInt=(value,name)=>{
  const n=Number(value);
  if(!Number.isInteger(n) || n<=0){
    throw new Error('Invalid prepConfig '+name+': '+String(value));
  }
  return n;
};

const buildFallbackRunContext=()=>{
  const TZ='America/Sao_Paulo';
  const now=new Date();
  const parts=new Intl.DateTimeFormat('en-CA',{
    timeZone:TZ,
    year:'numeric',
    month:'2-digit',
    day:'2-digit'
  }).formatToParts(now);
  const m={};
  for(const p of parts){
    m[p.type]=p.value;
  }

  const year=Number(m.year);
  const month=Number(m.month);
  const day=Number(m.day);
  let compYear=year;
  let compMonth=month-1;
  if(compMonth===0){
    compMonth=12;
    compYear=year-1;
  }

  const mm=String(compMonth).padStart(2,'0');
  const competenciaYMD=compYear+'-'+mm+'-01';
  const daysInCompMonth=new Date(Date.UTC(compYear,compMonth,0)).getUTCDate();

  return {
    startedAt:now.toISOString(),
    timezone:TZ,
    todayDay:day,
    competenciaYMD,
    compStart:competenciaYMD,
    compEnd:compYear+'-'+mm+'-'+String(daysInCompMonth).padStart(2,'0'),
    flags:{
      maxRulesPages:50,
      maxPrefetchPages:50,
      rulesPageSize:50,
      prefetchPageSize:200
    },
    metrics:{...METRICS_DEFAULTS},
    logs:[],
    errors:[]
  };
};

const clone=(obj)=>JSON.parse(JSON.stringify(obj));
const fallback=buildFallbackRunContext();

const input=($json && typeof $json==='object' && !Array.isArray($json)) ? $json : {};
const incomingRunContext=(input.runContext && typeof input.runContext==='object' && !Array.isArray(input.runContext)) ? input.runContext : null;
const callerInput=(input.caller && typeof input.caller==='object' && !Array.isArray(input.caller)) ? input.caller : {};
const prepInput=(input.prepConfig && typeof input.prepConfig==='object' && !Array.isArray(input.prepConfig)) ? input.prepConfig : {};

const runContext=incomingRunContext ? clone(incomingRunContext) : fallback;
const normalizationNotes=[];
runContext.timezone=String(runContext.timezone || fallback.timezone || 'America/Sao_Paulo');
runContext.startedAt=String(runContext.startedAt || nowIso);
runContext.todayDay=normalizeNumber(runContext.todayDay,fallback.todayDay,1,31);
runContext.competenciaYMD=normalizeIsoDate(runContext.competenciaYMD,fallback.competenciaYMD,'competenciaYMD',normalizationNotes);
runContext.compStart=normalizeIsoDate(runContext.compStart || runContext.competenciaYMD,fallback.compStart,'compStart',normalizationNotes);
runContext.compEnd=normalizeIsoDate(runContext.compEnd,fallback.compEnd,'compEnd',normalizationNotes);
if(runContext.compStart > runContext.compEnd){
  normalizationNotes.push({field:'competencia_window',from:{compStart:runContext.compStart,compEnd:runContext.compEnd},to:{compStart:fallback.compStart,compEnd:fallback.compEnd}});
  runContext.compStart=fallback.compStart;
  runContext.compEnd=fallback.compEnd;
}

runContext.flags=(runContext.flags && typeof runContext.flags==='object' && !Array.isArray(runContext.flags)) ? runContext.flags : {};
runContext.flags.maxRulesPages=normalizeNumber(runContext.flags.maxRulesPages,50,1,1000);
runContext.flags.maxPrefetchPages=normalizeNumber(runContext.flags.maxPrefetchPages,50,1,1000);
runContext.flags.rulesPageSize=normalizeNumber(runContext.flags.rulesPageSize,50,1,200);
runContext.flags.prefetchPageSize=normalizeNumber(runContext.flags.prefetchPageSize,200,1,200);
runContext.metrics=(runContext.metrics && typeof runContext.metrics==='object' && !Array.isArray(runContext.metrics)) ? runContext.metrics : {};
for(const [k,v] of Object.entries(METRICS_DEFAULTS)){
  runContext.metrics[k]=Number.isFinite(Number(runContext.metrics[k])) ? Number(runContext.metrics[k]) : v;
}
runContext.metrics.unexpectedStateErrors=Number(runContext.metrics.unexpectedStateErrors || 0);
runContext.logs=Array.isArray(runContext.logs) ? runContext.logs : [];
runContext.errors=Array.isArray(runContext.errors) ? runContext.errors : [];

const prepConfig={
  rulesPhaseId:validatePositiveInt(prepInput.rulesPhaseId ?? 341313813,'rulesPhaseId'),
  invoicesPipeId:validatePositiveInt(prepInput.invoicesPipeId ?? 306859731,'invoicesPipeId'),
  competenciaFieldId:String(prepInput.competenciaFieldId || 'data_de_compet_ncia').trim(),
  ruleLinkFieldId:String(prepInput.ruleLinkFieldId || 'id_da_regra_de_faturamento').trim()
};
if(!prepConfig.competenciaFieldId){
  throw new Error('Invalid prepConfig competenciaFieldId (blank)');
}
if(!prepConfig.ruleLinkFieldId){
  throw new Error('Invalid prepConfig ruleLinkFieldId (blank)');
}

const prepMeta={
  source:incomingRunContext ? 'caller' : 'fallback',
  callerWorkflowId:callerInput.workflowId != null ? String(callerInput.workflowId) : null,
  callerWorkflowName:callerInput.workflowName != null ? String(callerInput.workflowName) : null,
  callerExecutionId:callerInput.executionId != null ? String(callerInput.executionId) : null,
  prepExecutionId:execId,
  normalizedAt:nowIso
};

runContext.logs.push({
  ts:nowIso,
  level:'info',
  event:'prep_init',
  source:prepMeta.source,
  callerExecutionId:prepMeta.callerExecutionId,
  competenciaYMD:runContext.competenciaYMD
});

if(!incomingRunContext){
  runContext.logs.push({
    ts:nowIso,
    level:'warn',
    event:'prep_init_without_caller_context',
    reason:'incoming_run_context_missing'
  });
}
if(normalizationNotes.length>0){
  runContext.metrics.unexpectedStateErrors += normalizationNotes.length;
  runContext.logs.push({
    ts:nowIso,
    level:'warn',
    event:'prep_run_context_normalized',
    fields:normalizationNotes.map((x)=>x.field),
    details:normalizationNotes
  });
}

if(!isIsoDate(runContext.compStart) || !isIsoDate(runContext.compEnd) || runContext.compStart>runContext.compEnd){
  runContext.metrics.unexpectedStateErrors += 1;
  runContext.errors.push({event:'prep_invalid_comp_window',details:{compStart:runContext.compStart,compEnd:runContext.compEnd}});
  throw new Error('Invalid competencia window after normalization');
}

sd.prepRuns=(sd.prepRuns && typeof sd.prepRuns==='object' && !Array.isArray(sd.prepRuns)) ? sd.prepRuns : {};
for(const [key,state] of Object.entries(sd.prepRuns)){
  const startedAt=state?.runContext?.startedAt || state?.stateStartedAt || null;
  const ageMs=startedAt ? (Date.now()-Date.parse(startedAt)) : Number.POSITIVE_INFINITY;
  if(!Number.isFinite(ageMs) || ageMs > 24*60*60*1000){
    delete sd.prepRuns[key];
  }
}

sd.prepRuns[execId]={
  runContext,
  rules:[],
  existingRuleIds:{},
  prepMeta,
  prepConfig,
  stateStartedAt:nowIso
};

return [{json:{
  execId,
  runContext,
  prepMeta,
  prepConfig,
  after:null,
  prefetchAfter:null
}}];

const sd=$getWorkflowStaticData('global');
const execId=String($execution.id ?? 'manual');
const state=sd.prepRuns?.[execId];
if(!state){
  throw new Error('Missing state for execution '+execId);
}

const runContext=state.runContext;
runContext.metrics=runContext.metrics || {};
runContext.logs=Array.isArray(runContext.logs) ? runContext.logs : [];
runContext.errors=Array.isArray(runContext.errors) ? runContext.errors : [];
state.rules=Array.isArray(state.rules) ? state.rules : [];

const nowIso=new Date().toISOString();
const gqlErrors=Array.isArray($json.errors) ? $json.errors : [];
if(gqlErrors.length>0){
  runContext.errors.push({event:'rules_query_error',reason:'graphql_errors',errors:gqlErrors});
  runContext.logs.push({ts:nowIso,level:'error',event:'rules_query_error',reason:'graphql_errors',errorsCount:gqlErrors.length});
  throw new Error('Rules query returned GraphQL errors: '+JSON.stringify(gqlErrors));
}

const cards=$json.data?.phase?.cards;
if(!cards || !Array.isArray(cards.edges) || typeof cards.pageInfo!=='object' || cards.pageInfo===null){
  runContext.errors.push({event:'rules_query_error',reason:'invalid_shape',details:$json.data ?? null});
  runContext.logs.push({ts:nowIso,level:'error',event:'rules_query_invalid_shape',reason:'invalid_shape'});
  throw new Error('Invalid GraphQL shape for rules listing');
}

const edges=cards.edges;
const pi=cards.pageInfo;
const sanitizeCursor=(c)=>{
  if(c===undefined || c===null) return null;
  const s=String(c).trim();
  if(!s || s.toLowerCase()==='null') return null;
  return s;
};

let hasNextPage=pi.hasNextPage===true;
let endCursor=sanitizeCursor(pi.endCursor);
let stopReason=null;

const pageNum=Number(runContext.metrics.rulesPages || 0) + 1;
runContext.metrics.rulesPages=pageNum;

for(const e of edges){
  if(e?.node?.id) state.rules.push(e.node);
}

if(edges.length===0){
  hasNextPage=false;
  stopReason='empty_page';
}

const lastCursor=runContext.lastRulesCursor ?? null;
if(hasNextPage && endCursor===null){
  hasNextPage=false;
  stopReason='missing_end_cursor';
  runContext.logs.push({ts:nowIso,level:'warn',event:'rules_cursor_missing',page:pageNum});
}else if(hasNextPage && lastCursor!==null && String(endCursor)===String(lastCursor)){
  hasNextPage=false;
  stopReason='stuck_cursor';
  runContext.logs.push({ts:nowIso,level:'warn',event:'rules_cursor_stuck',page:pageNum,endCursor:String(endCursor)});
}
runContext.lastRulesCursor=endCursor;

const MAX_PAGES=Math.max(1,Number(runContext.flags?.maxRulesPages || 50));
if(pageNum>=MAX_PAGES && hasNextPage){
  hasNextPage=false;
  stopReason='max_pages_reached';
  runContext.logs.push({ts:nowIso,level:'warn',event:'rules_page_cap_reached',maxPages:MAX_PAGES,page:pageNum});
}

runContext.logs.push({
  ts:nowIso,
  level:'info',
  event:'rules_page_fetched',
  page:pageNum,
  edgesCount:edges.length,
  accumulatedRules:state.rules.length,
  hasNextPage,
  endCursor,
  stopReason
});

return [{
  json:{
    hasNextPage,
    endCursor,
    after:(hasNextPage ? endCursor : null),
    edgesCount:edges.length,
    page:pageNum,
    stopReason
  }
}];

const sd=$getWorkflowStaticData('global');
const execId=String($execution.id ?? 'manual');
const state=sd.prepRuns?.[execId];
if(!state){
  throw new Error('Missing state for execution '+execId);
}

const runContext=state.runContext;
runContext.metrics=runContext.metrics || {};
runContext.logs=Array.isArray(runContext.logs) ? runContext.logs : [];
runContext.errors=Array.isArray(runContext.errors) ? runContext.errors : [];

const rules=Array.isArray(state.rules) ? state.rules : [];
runContext.metrics.rulesTotal=rules.length;

const today=String(runContext.todayDay);
const existing=state.existingRuleIds || {};
const eligibleRules=[];
const ineligibleRules=[];
const log=(obj)=>runContext.logs.push({ts:new Date().toISOString(),...obj});
const isBlankToken=(value)=>{
  const s=String(value ?? '').trim().toLowerCase();
  return s==='' || s==='null' || s==='undefined' || s==='nan';
};

const counters={
  skippedDay:0,
  skippedExisting:0,
  invalidRuleId:0,
  emptyItemTemplates:0
};
const ineligibleByReason={};
const countIneligibleReason=(reason)=>{
  const key=String(reason || 'unknown_reason');
  ineligibleByReason[key]=Number(ineligibleByReason[key] || 0) + 1;
};

const fieldMap=(fields)=>{
  const m={};
  for(const f of (fields || [])){
    const fid=f&&f.field ? f.field.id : null;
    if(fid) m[fid]=f;
  }
  return m;
};
const pickScalar=(f)=>{
  if(!f) return null;
  const rv=f.report_value;
  return (rv!==undefined && rv!==null && String(rv).trim()!=='') ? rv : f.value;
};
const extractIds=(f)=>{
  if(!f) return [];
  const av=f.array_value;
  const ids=[];
  const push=(x)=>{
    if(x===undefined || x===null) return;
    if(typeof x==='object'){
      if(x.id!=null) ids.push(String(x.id));
      else if(x.value!=null) ids.push(String(x.value));
      else if(x.label!=null) ids.push(String(x.label));
      else ids.push(JSON.stringify(x));
    }else{
      ids.push(String(x));
    }
  };

  if(Array.isArray(av)){
    for(const x of av) push(x);
  }else{
    const v=pickScalar(f);
    if(Array.isArray(v)){
      for(const x of v) push(x);
    }else if(typeof v==='string'){
      const ms=v.match(/[0-9]+/g);
      if(ms) for(const x of ms) ids.push(String(x));
      else if(v.trim()!=='') ids.push(v.trim());
    }else if(v!=null){
      push(v);
    }
  }

  return Array.from(new Set(ids.filter((s)=>s && String(s).trim()!==''))).map(String);
};

const registerIneligible=(payload)=>{
  const reason=String(payload?.reason || 'unknown_reason');
  countIneligibleReason(reason);
  ineligibleRules.push({
    ...payload,
    reason,
    competenciaYMD:runContext.competenciaYMD,
    compStart:runContext.compStart,
    compEnd:runContext.compEnd
  });
};

for(const r of rules){
  const ridRaw=String(r?.id ?? '').trim();
  const ruleTitle=String(r?.title || '');

  if(isBlankToken(ridRaw)){
    counters.invalidRuleId += 1;
    runContext.metrics.rulesInvalid=Number(runContext.metrics.rulesInvalid || 0) + 1;
    runContext.errors.push({
      event:'rule_invalid_id',
      reason:'missing_rule_id',
      details:{ruleTitle}
    });
    log({
      level:'error',
      event:'rule_skip_invalid_id',
      reason:'missing_rule_id',
      ruleTitle
    });
    registerIneligible({
      ruleId:null,
      ruleTitle,
      diaGeracao:null,
      reason:'missing_rule_id',
      reasonDetail:{ruleIdRaw:ridRaw || null},
      prefetchDecision:'invalid_rule'
    });
    continue;
  }

  const rid=String(ridRaw);
  const fm=fieldMap(r.fields);
  const dia=String(pickScalar(fm['dia_de_gera_o_da_fatura']) || '').trim();
  if(dia!==today){
    counters.skippedDay += 1;
    runContext.metrics.rulesSkippedDay=Number(runContext.metrics.rulesSkippedDay || 0) + 1;
    log({level:'info',event:'rule_skip_day',ruleId:rid,diaGeracao:dia,expectedDay:today,reason:'billing_day_mismatch'});
    registerIneligible({
      ruleId:rid,
      ruleTitle,
      diaGeracao:dia,
      reason:'billing_day_mismatch',
      reasonDetail:{expectedDay:today,actualDay:dia},
      prefetchDecision:'billing_day_mismatch'
    });
    continue;
  }

  if(existing[rid]){
    counters.skippedExisting += 1;
    runContext.metrics.rulesSkippedExisting=Number(runContext.metrics.rulesSkippedExisting || 0) + 1;
    log({level:'info',event:'rule_skip_existing_invoice',ruleId:rid,competenciaYMD:runContext.competenciaYMD,prefetchDecision:'already_has_invoice',reason:'prefetch_found_invoice'});
    registerIneligible({
      ruleId:rid,
      ruleTitle,
      diaGeracao:dia,
      reason:'prefetch_found_invoice',
      reasonDetail:{competenciaYMD:runContext.competenciaYMD},
      prefetchDecision:'already_has_invoice'
    });
    continue;
  }

  const itemIds=extractIds(fm['itens_da_fatura']);
  if(itemIds.length===0){
    counters.emptyItemTemplates += 1;
    log({level:'warn',event:'rule_no_item_templates',ruleId:rid,reason:'empty_item_template_list'});
  }

  eligibleRules.push({
    ruleId:rid,
    ruleTitle,
    diaGeracao:dia,
    itemTemplateIds:itemIds,
    ruleFields:fm,
    competenciaYMD:runContext.competenciaYMD,
    compStart:runContext.compStart,
    compEnd:runContext.compEnd,
    prefetchDecision:'new_rule_candidate'
  });
}

runContext.metrics.rulesEligible=eligibleRules.length;
runContext.metrics.rulesIneligible=ineligibleRules.length;
log({
  level:'info',
  event:'rules_classified',
  eligible:eligibleRules.length,
  ineligible:ineligibleRules.length,
  totalRules:rules.length,
  counters,
  ineligibleByReason
});

if(eligibleRules.length===0){
  runContext.logs.push({
    ts:new Date().toISOString(),
    level:'info',
    event:'prep_completed_no_eligible_rules',
    reason:'no_rule_eligible_after_filters',
    counters,
    ineligibleByReason
  });
}

return [{json:{
  kind:'prep_classification',
  eligibleRules,
  ineligibleRules,
  counters,
  ineligibleByReason
}}];

const sd=$getWorkflowStaticData('global');
const execId=String($execution.id ?? 'manual');
const state=sd.prepRuns?.[execId];
if(!state){
  throw new Error('Missing state for execution '+execId);
}

const runContext=state.runContext || {};
const prepMeta=state.prepMeta || {};
runContext.logs=Array.isArray(runContext.logs) ? runContext.logs : [];
runContext.errors=Array.isArray(runContext.errors) ? runContext.errors : [];

const items=$input.all();
const payloadItem=items.find((it)=>it && it.json && typeof it.json==='object' && !Array.isArray(it.json));
const payload=(payloadItem && payloadItem.json && typeof payloadItem.json==='object' && !Array.isArray(payloadItem.json)) ? payloadItem.json : {};
const eligibleRules=Array.isArray(payload.eligibleRules) ? payload.eligibleRules : [];
const ineligibleRules=Array.isArray(payload.ineligibleRules) ? payload.ineligibleRules : [];

const derivedIneligibleByReason={};
for(const rule of ineligibleRules){
  const reason=String(rule?.reason || 'unknown_reason');
  derivedIneligibleByReason[reason]=Number(derivedIneligibleByReason[reason] || 0) + 1;
}
const providedIneligibleByReason=(payload.ineligibleByReason && typeof payload.ineligibleByReason==='object' && !Array.isArray(payload.ineligibleByReason)) ? payload.ineligibleByReason : null;
const ineligibleByReason=providedIneligibleByReason || derivedIneligibleByReason;

const eligibleCount=Number(runContext.metrics?.rulesEligible || eligibleRules.length || 0);
const ineligibleCount=Number(runContext.metrics?.rulesIneligible || ineligibleRules.length || 0);
const rulesTotal=Number(runContext.metrics?.rulesTotal || (eligibleCount + ineligibleCount));
const errorCount=runContext.errors.length;
const logCount=runContext.logs.length;

runContext.logs.push({
  ts:new Date().toISOString(),
  level:'info',
  event:'prep_completed',
  eligible:eligibleCount,
  ineligible:ineligibleCount,
  rulesTotal,
  errorCount,
  logCount,
  ineligibleByReason,
  contractVersion:'fin_v2'
});

const clone=(obj)=>JSON.parse(JSON.stringify(obj));
const runContextSnapshot=clone(runContext);
const prepMetaSnapshot=clone(prepMeta);
const prepContext={
  eligibleCount,
  ineligibleCount,
  ineligibleByReason,
  rulesTotal,
  errorCount,
  logCount:runContextSnapshot.logs?.length ?? logCount
};

const baseTrace={
  parentExecutionId:prepMetaSnapshot.callerExecutionId != null ? String(prepMetaSnapshot.callerExecutionId) : null,
  workflowExecutionId:execId,
  procKey:null
};

const out=[];
out.push({
  json:{
    contractVersion:'fin_v2',
    itemType:'prep_summary',
    trace:{...baseTrace},
    runContext:runContextSnapshot,
    ruleContext:null,
    result:{
      status:'processed',
      reason:'prep_summary',
      prepContext
    },
    prepMeta:prepMetaSnapshot
  }
});

for(const rule of eligibleRules){
  const ruleContext={
    ruleId:rule?.ruleId ?? null,
    ruleTitle:rule?.ruleTitle ?? null,
    diaGeracao:rule?.diaGeracao ?? null,
    itemTemplateIds:Array.isArray(rule?.itemTemplateIds) ? rule.itemTemplateIds : [],
    ruleFields:rule?.ruleFields ?? {},
    competenciaYMD:rule?.competenciaYMD ?? runContextSnapshot.competenciaYMD ?? null,
    compStart:rule?.compStart ?? runContextSnapshot.compStart ?? null,
    compEnd:rule?.compEnd ?? runContextSnapshot.compEnd ?? null,
    prefetchDecision:rule?.prefetchDecision ?? 'new_rule_candidate'
  };

  out.push({
    json:{
      contractVersion:'fin_v2',
      itemType:'rule_candidate',
      trace:{...baseTrace},
      runContext:runContextSnapshot,
      ruleContext,
      result:{
        status:'processed',
        reason:'ready_for_processing',
        prepContext
      },
      prepMeta:prepMetaSnapshot
    }
  });
}

for(const rule of ineligibleRules){
  const reason=String(rule?.reason || 'prep_ineligible');
  const ruleContext={
    ruleId:rule?.ruleId ?? null,
    ruleTitle:rule?.ruleTitle ?? null,
    diaGeracao:rule?.diaGeracao ?? null,
    itemTemplateIds:Array.isArray(rule?.itemTemplateIds) ? rule.itemTemplateIds : [],
    ruleFields:rule?.ruleFields ?? {},
    competenciaYMD:rule?.competenciaYMD ?? runContextSnapshot.competenciaYMD ?? null,
    compStart:rule?.compStart ?? runContextSnapshot.compStart ?? null,
    compEnd:rule?.compEnd ?? runContextSnapshot.compEnd ?? null,
    prefetchDecision:rule?.prefetchDecision ?? null
  };

  out.push({
    json:{
      contractVersion:'fin_v2',
      itemType:'rule_result',
      trace:{...baseTrace},
      runContext:runContextSnapshot,
      ruleContext,
      result:{
        status:'skipped',
        reason,
        invoiceId:null,
        createdItemIds:[],
        ineligibility:{
          reason,
          details:rule?.reasonDetail ?? null
        },
        prepContext
      },
      prepMeta:prepMetaSnapshot
    }
  });
}

delete sd.prepRuns[execId];
return out;

const sd=$getWorkflowStaticData('global');
const execId=String($execution.id ?? 'manual');
const state=sd.prepRuns?.[execId];
if(!state){
  throw new Error('Missing state for execution '+execId);
}

const runContext=state.runContext;
runContext.metrics=runContext.metrics || {};
runContext.logs=Array.isArray(runContext.logs) ? runContext.logs : [];
runContext.errors=Array.isArray(runContext.errors) ? runContext.errors : [];
runContext.metrics.invoicesPrefetchCalls=Number(runContext.metrics.invoicesPrefetchCalls || 0);
runContext.metrics.invoicesPrefetchCount=Number(runContext.metrics.invoicesPrefetchCount || 0);

const nowIso=new Date().toISOString();
const gqlErrors=Array.isArray($json.errors) ? $json.errors : [];
if(gqlErrors.length>0){
  runContext.errors.push({event:'prefetch_query_error',reason:'graphql_errors',errors:gqlErrors});
  runContext.logs.push({ts:nowIso,level:'error',event:'prefetch_query_error',reason:'graphql_errors',errorsCount:gqlErrors.length});
  throw new Error('Prefetch query returned GraphQL errors: '+JSON.stringify(gqlErrors));
}

const find=$json.data?.findCards;
if(!find || !Array.isArray(find.edges) || typeof find.pageInfo!=='object' || find.pageInfo===null){
  runContext.errors.push({event:'prefetch_query_error',reason:'invalid_shape',details:$json.data ?? null});
  runContext.logs.push({ts:nowIso,level:'error',event:'prefetch_query_invalid_shape',reason:'invalid_shape'});
  throw new Error('Invalid GraphQL shape for invoice prefetch');
}

const edges=find.edges;
const pageInfo=find.pageInfo;
const sanitizeCursor=(c)=>{
  if(c===undefined || c===null) return null;
  const s=String(c).trim();
  if(!s || s.toLowerCase()==='null') return null;
  return s;
};

const existing=state.existingRuleIds || {};
const getField=(fields,id)=>{ for(const f of (fields || [])) if(f?.field?.id===id) return f; return null; };
const pick=(f)=>{ if(!f) return null; const rv=f.report_value; return (rv!==undefined && rv!==null && String(rv).trim()!=='') ? rv : f.value; };
const toId=(v)=>{ if(v==null) return null; const s=String(v); const m=s.match(/[0-9]+/); return m ? m[0] : s.trim(); };

let missingRuleLinks=0;
const ruleLinkFieldId=String(state.prepConfig?.ruleLinkFieldId || 'id_da_regra_de_faturamento');
for(const e of edges){
  const node=e?.node ?? null;
  if(!node){
    missingRuleLinks += 1;
    continue;
  }
  const f=getField(node.fields,ruleLinkFieldId);
  const rid=toId(pick(f));
  if(rid){
    existing[rid]=true;
  }else{
    missingRuleLinks += 1;
  }
}
state.existingRuleIds=existing;
if(missingRuleLinks>0){
  runContext.metrics.prefetchInvoicesMissingRuleLink=Number(runContext.metrics.prefetchInvoicesMissingRuleLink || 0) + missingRuleLinks;
  runContext.logs.push({
    ts:nowIso,
    level:'warn',
    event:'prefetch_invoice_without_rule_link',
    count:missingRuleLinks,
    ruleLinkFieldId
  });
}

let hasNextPage=pageInfo.hasNextPage===true;
let endCursor=sanitizeCursor(pageInfo.endCursor);
let stopReason=null;

const MAX_PAGES=Math.max(1,Number(runContext.flags?.maxPrefetchPages || 50));
const callNum=runContext.metrics.invoicesPrefetchCalls + 1;
runContext.metrics.invoicesPrefetchCalls=callNum;
runContext.metrics.invoicesPrefetchCount += edges.length;

if(edges.length===0){
  hasNextPage=false;
  stopReason='empty_page';
}

const lastCursor=runContext.lastInvoicesPrefetchCursor ?? null;
if(hasNextPage && endCursor===null){
  hasNextPage=false;
  stopReason='missing_end_cursor';
  runContext.logs.push({ts:nowIso,level:'warn',event:'prefetch_cursor_missing',callNum});
}else if(hasNextPage && lastCursor!==null && String(endCursor)===String(lastCursor)){
  hasNextPage=false;
  stopReason='stuck_cursor';
  runContext.logs.push({ts:nowIso,level:'warn',event:'prefetch_cursor_stuck',callNum,endCursor:String(endCursor)});
}
runContext.lastInvoicesPrefetchCursor=endCursor;

if(callNum>=MAX_PAGES && hasNextPage){
  hasNextPage=false;
  stopReason='max_pages_reached';
  runContext.logs.push({ts:nowIso,level:'warn',event:'prefetch_page_cap_reached',maxPages:MAX_PAGES,callNum});
}

runContext.logs.push({
  ts:nowIso,
  level:'info',
  event:'prefetch_invoices',
  competenciaYMD: runContext.competenciaYMD,
  count: edges.length,
  uniqueRules: Object.keys(existing).length,
  hasNextPage,
  endCursor,
  stopReason,
  missingRuleLinks
});

return [{json:{
  prefetchAfter:(hasNextPage ? endCursor : null),
  prefetchHasNextPage:hasNextPage,
  prefetchStopReason:stopReason
}}];
